export interface FrontendService {
  // Get hero information
  GetHero(request: GetHeroRequest): Promise<GetHeroResponse>;
  // Get a colourway by its public base SKU.
  GetColorway(request: GetColorwayRequest): Promise<GetColorwayResponse>;
  // Get paged colourways.
  GetColorwaysPaged(request: GetColorwaysPagedRequest): Promise<GetColorwaysPagedResponse>;
  // Submit an order
  SubmitOrder(request: SubmitOrderRequest): Promise<SubmitOrderResponse>;
  // Retrieves an order by its ID
  GetOrderByUUIDAndEmail(request: GetOrderByUUIDAndEmailRequest): Promise<GetOrderByUUIDAndEmailResponse>;
  ValidateOrderItemsInsert(request: ValidateOrderItemsInsertRequest): Promise<ValidateOrderItemsInsertResponse>;
  ValidateOrderByUUID(request: ValidateOrderByUUIDRequest): Promise<ValidateOrderByUUIDResponse>;
  // Generate an invoice for the order or return the existing one
  GetOrderInvoice(request: GetOrderInvoiceRequest): Promise<GetOrderInvoiceResponse>;
  // Cancel an invoice for the order
  CancelOrderInvoice(request: CancelOrderInvoiceRequest): Promise<CancelOrderInvoiceResponse>;
  // Cancel order by user with reason
  CancelOrderByUser(request: CancelOrderByUserRequest): Promise<CancelOrderByUserResponse>;
  // Subscribe to the newsletter
  SubscribeNewsletter(request: SubscribeNewsletterRequest): Promise<SubscribeNewsletterResponse>;
  // Unsubscribe from the newsletter
  UnsubscribeNewsletter(request: UnsubscribeNewsletterRequest): Promise<UnsubscribeNewsletterResponse>;
  // NotifyMe adds an email to the waitlist for a specific product/size when out of stock
  NotifyMe(request: NotifyMeRequest): Promise<NotifyMeResponse>;
  // GetArchive retrieves an archive by its stable public code (the /timeline URL tail).
  GetArchive(request: GetArchiveRequest): Promise<GetArchiveResponse>;
  // GetArchivesPaged retrieves paged archives. NOTE on ordering: grpc-gateway's mux prepends
  // handlers, so the LAST-declared route for a method wins. The literal `/archive/paged` GET must be
  // declared AFTER the `/archive/{code}` GET — otherwise {code} captures "paged" (beta smoke caught
  // exactly that shadowing).
  GetArchivesPaged(request: GetArchivesPagedRequest): Promise<GetArchivesPagedResponse>;
  // Submit a support ticket
  SubmitSupportTicket(request: SubmitSupportTicketRequest): Promise<SubmitSupportTicketResponse>;
  // Submit reviews for a delivered order (order-level + per-item, requires delivered order + buyer email)
  SubmitOrderReview(request: SubmitOrderReviewRequest): Promise<SubmitOrderReviewResponse>;
  RequestAccountLogin(request: RequestAccountLoginRequest): Promise<RequestAccountLoginResponse>;
  VerifyAccountLoginCode(request: VerifyAccountLoginCodeRequest): Promise<VerifyAccountLoginResponse>;
  VerifyAccountMagicLink(request: VerifyAccountMagicLinkRequest): Promise<VerifyAccountLoginResponse>;
  RefreshAccountSession(request: RefreshAccountSessionRequest): Promise<RefreshAccountSessionResponse>;
  // RevokeAccountSession logs out this client: invalidates the Bearer access token and revokes this refresh token's rotation family (other devices unchanged). Requires Bearer token + refresh_token.
  RevokeAccountSession(request: RevokeAccountSessionRequest): Promise<RevokeAccountSessionResponse>;
  GetAccount(request: GetAccountRequest): Promise<GetAccountResponse>;
  UpdateAccount(request: UpdateAccountRequest): Promise<UpdateAccountResponse>;
  ListSavedAddresses(request: ListSavedAddressesRequest): Promise<ListSavedAddressesResponse>;
  AddSavedAddress(request: AddSavedAddressRequest): Promise<AddSavedAddressResponse>;
  UpdateSavedAddress(request: UpdateSavedAddressRequest): Promise<UpdateSavedAddressResponse>;
  DeleteSavedAddress(request: DeleteSavedAddressRequest): Promise<DeleteSavedAddressResponse>;
  SetDefaultSavedAddress(request: SetDefaultSavedAddressRequest): Promise<SetDefaultSavedAddressResponse>;
  ListMyOrders(request: ListMyOrdersRequest): Promise<ListMyOrdersResponse>;
}

